+#[cfg(target_arch = "wasm32")]
+fn browser_host_listener_error(err: &JsValue, op: &str) -> io::Error {
+    let detail = err.as_string().unwrap_or_else(|| format!("{err:?}"));
+    io::Error::other(format!("{op} failed: {detail}"))
+}
